    computeCount = 0;
    reaction::batch([&]() {
        a.value(batchA);
        b.value(batchB);
    });
    int countAfterBatch = computeCount;

    // 9. Return final sum and both recomputation counts
    return std::make_tuple(sum.get(), countAfterNonBatch, countAfterBatch);
