  EXPECT_TRUE(snapshot.multiplyReportedChange);
  EXPECT_FALSE(snapshot.andReportedChange);
  EXPECT_TRUE(snapshot.leftShiftReportedChange);
  EXPECT_TRUE(snapshot.incrementReportedChange);
}

}  // namespace test_reaction

